async (params, browser) => {
  // Open page
  await browser.open(`https://letterboxd.com/film/${params.film_slug}/`)

  // Wait for content
  await browser.waitForSelector('h1.primaryname, h1.filmtitle, h1', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1.primaryname span.name, h1.filmtitle, h1')?.textContent?.trim()||''; const year = document.querySelector('div.releaseyear a, small.number a')?.textContent?.trim()||''; const director = document.querySelector('a.text-sluglist[href*="/director/"], span.text-sluglist a, a[href*="/director/"]')?.textContent?.trim()||''; const rating = document.querySelector('span.average-rating a, span.average-rating')?.textContent?.trim()||''; const tagline = document.querySelector('div.tagline')?.textContent?.trim()||''; const desc = document.querySelector('div.truncate p, div.body-text p')?.textContent?.trim()?.substring(0,1000)||''; const genres = Array.from(document.querySelectorAll('div#tab-genres a, a[href*="/films/genre/"]')).map(g=>g.textContent.trim()); const cast = Array.from(document.querySelectorAll('div#tab-cast a.tooltip, a[href*="/actor/"]')).slice(0,15).map(a=>a.textContent.trim()); return { title, year, director, rating, tagline, description: desc, genres, cast, url: window.location.href }`)

  return page_data
}
